Voici une implémentation possible de la méthode `TransformToQuestion` en utilisant les concepts de base de C#:

```
public string TransformToQuestion(string sentence)
{
  // Supprimer les espaces inutiles à la fin de la chaîne
  sentence = sentence.TrimEnd();

  // Extraire le dernier mot de la phrase
  string lastWord = sentence.Split(' ').Last();

  // Convertir le dernier mot en minuscule
  lastWord = lastWord.ToLower();

  // Déterminer si le dernier mot est "je"
  bool isI = lastWord == "je";

  // Déterminer si le dernier mot se termine par un point
  bool endsWithPeriod = sentence.EndsWith(".");

  // Supprimer le dernier caractère (point ou point d'interrogation) si présent
  if (endsWithPeriod || sentence.EndsWith(" ?"))
  {
    sentence = sentence.Substring(0, sentence.Length - 1);
  }

  // Ajouter le point d'interrogation final
  sentence += " ?";

  // Modifier la première lettre en majuscule
  sentence = char.ToUpper(sentence[0]) + sentence.Substring(1);

  // Construire le résultat final en fonction de la présence du mot "je"
  if (isI)
  {
    return "Aimes-tu" + sentence.Substring(2);
  }
  else
  {
    return "Aimez-vous" + sentence.Substring(2);
  }
}
```

