import java.util.ArrayList;

public class EmploymentTrends {
   public static void main(String[] args) {
      // Create an ArrayList for rural and urban employment data
      ArrayList<Double> ruralEmploymentData = new ArrayList<Double>();
      ArrayList<Double> urbanEmploymentData = new ArrayList<Double>();

      // Populate rural and urban employment data
      ruralEmploymentData.add(75.0); // 75% of rural jobs were low-skill before automation
      urbanEmploymentData.add(50.0); // 50% of urban jobs were low-skill before automation

      // Define the impact of automation on employment trends
