      double newRuralEmployment = (100 - ruralAutomationImpact) * (ruralEmploymentData.get(0)/100);
      ruralEmploymentData.add(newRuralEmployment);

      double newUrbanEmployment = (100 - urbanAutomationImpact) * (urbanEmploymentData.get(0)/100);
      urbanEmploymentData.add(newUrbanEmployment);

      // Print out the updated employment data
      System.out.println("Rural Employment Data (before and after automation):");
      System.out.println(ruralEmploymentData.get(0) + "% (before) -> " + ruralEmploymentData.get(1) + "% (after)");

      System.out.println("\nUrban Employment Data (before and after automation):");
